using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Blog>(entity =>
        {
            // Breaking change #1: EF 9 renamed "Discriminator" to "$type".
            // Existing documents use "Discriminator", so we must preserve it.
            entity.HasDiscriminator().HasValue("Blog");
            entity.Property<string>("$type").ToJsonProperty("Discriminator");

            // Breaking change #2: EF 9 changed id format from "EntityType|Key" to just "Key".
            // Existing documents use "Blog|1" format, so we opt back in.
            entity.HasPartitionKey(b => b.Id);
            entity.Property(b => b.Id)
                  .ToJsonProperty("id")
                  .HasValueGenerator<LegacyIdValueGenerator>();

            // Breaking change #3: EF 9 uses hierarchical partition keys and removed
            // support for the sync-stored-procedure path. No explicit fix needed here
            // unless you rely on that feature.

            // Breaking change #4: HasIndex is now an error on Cosmos (was a no-op).
            // REMOVED: entity.HasIndex(b => b.Name);
        });
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; }  }

